const MIN_INPUT_FLASH_MS = 80;
const inputFlashStartedAt = new Map<string, number>();
const inputFlashTimers = new Map<string, number>();

function setInputFlash(attr: string, isRelease: boolean): void {
  const targets = [
    document.querySelector(`.judgment-icon.${attr}`),
    document.querySelector(`.touch-lane-hitarea.${attr}`),
  ].filter(Boolean) as HTMLElement[];
  const clearTimer = () => {
    const timer = inputFlashTimers.get(attr);
    if (timer) window.clearTimeout(timer);
    inputFlashTimers.delete(attr);
  };

  if (!isRelease) {
    clearTimer();
    inputFlashStartedAt.set(attr, performance.now());
    targets.forEach((target) => target.classList.add("active"));
    return;
  }

  const elapsed = performance.now() - (inputFlashStartedAt.get(attr) || performance.now());
  const delay = Math.max(0, MIN_INPUT_FLASH_MS - elapsed);
  clearTimer();
  inputFlashTimers.set(
    attr,
    window.setTimeout(() => {
      targets.forEach((target) => target.classList.remove("active"));
      inputFlashStartedAt.delete(attr);
      inputFlashTimers.delete(attr);
    }, delay),
  );
}

